SELECT SUM(total_assertions) AS total_severe_assertions
FROM test_smells
WHERE severity = 'high';

SELECT test_smell_id, cause_of_smell 
FROM test_smells 
WHERE resolution_date IS NULL AND severity = 'high';

SELECT COUNT(DISTINCT test_smell_id) AS total_test_smells
FROM issue_tracking
WHERE priority = 'high';

SELECT COUNT(DISTINCT project_id) AS active_project_count
FROM user_projects
WHERE user_id = 1 AND is_active = 1;

SELECT test_smell_type_name
FROM test_smell_types
WHERE test_smell_type_id = 0;

SELECT COUNT(*) 
FROM test_run_details 
WHERE duration_ms > 500;
